<!DOCTYPE html>
<html>
<head>
<title>Simple Desktop Environment</title>
<style>
body {
  background-color: #303030;
  font-family: sans-serif;
  margin: 0;
}

#desktop {
  width: 80%;
  height: 90vh;
  margin: auto;
  display: flex;
  flex-direction: column;
}

#taskbar {
  background-color: #424242;
  padding: 10px;
  width: 80%;
  margin: 0 auto;
  display: flex;
  justify-content: space-between;
}

#open-files, #open-notepad {
  background-color: #555555;
  padding: 5px 10px;
  border-radius: 5px;
  cursor: pointer;
}

.win {
  width: 360px;
  height: 240px;
  background-color: #282828;
  position: absolute;
  top: 10%;
  left: 10%;
  border: 1px solid #666666;
  display: flex;
  flex-direction: column;
}

.win button {
  background-color: #777777;
  padding: 5px 10px;
  cursor: pointer;
}

#files-window, #notepad-window {
    display: none; /* Initially hidden */
}


/* Files App Styles */
#files-path {
  font-weight: bold;
  color: #ffffff;
  margin: 5px;
}

.fs-item {
  padding: 5px;
  cursor: pointer;
}

.fs-item:hover {
  background-color: #444444;
}

/* Notepad Styles */
#tabs {
  display: flex;
  border: 1px solid #666666;
  margin-bottom: 10px;
}

.tab {
  padding: 5px 10px;
  cursor: pointer;
  background-color: #383838;
  border-radius: 3px;
}

.tab.active {
  background-color: #424242;
}

#editor {
  width: 100%;
  height: 180px;
  padding: 5px;
  border: none;
  font-family: monospace;
  resize: vertical;
}
</style>
</head>
<body>

<div id="desktop">
  <div id="taskbar">
    <button id="open-files">Files</button>
    <button id="open-notepad">Notepad</button>
  </div>

  <div id="files-window" class="win">
    <p id="files-path">/home/user</p>
    <ul id="files-list">
      <li class="fs-item"><a href="#" onclick="navigate('/home/user/Documents')">Documents</a></li>
      <li class="fs-item"><a href="#" onclick="navigate('/home/user/Downloads')">Downloads</a></li>
      <li class="fs-item"><a href="#" onclick="navigate('/home/user/Pictures')">Pictures</a></li>
      <li class="fs-item"><a href="#" onclick="navigate('/home/user/Music')">Music</a></li>
    </ul>
    <button class="win-close" onclick="hideWindow()">Close</button>
  </div>

  <div id="notepad-window" class="win">
    <div id="tabs">
      <button class="tab active" onclick="activateTab(0)">Tab 1</button>
      <button class="tab" onclick="newTab()">New Tab</button>
    </div>
    <div id="editor"></div>
    <button class="win-close" onclick="hideWindow()">Close</button>
  </div>
</div>

<script>
const desktop = document.getElementById('desktop');
const taskbar = document.getElementById('taskbar');
const openFilesButton = document.getElementById('open-files');
const openNotepadButton = document.getElementById('open-notepad');
const filesWindow = document.getElementById('files-window');
const notepadWindow = document.getElementById('notepad-window');
const filesPathDisplay = document.getElementById('files-path');
const filesList = document.getElementById('files-list');
const editor = document.getElementById('editor');
const tabs = document.getElementById('tabs');
const newTabButton = document.getElementById('new-tab');

let currentTab = 0;
let tabContent = [];

function navigate(path) {
  filesPathDisplay.textContent = path;
  // Simulate file listing - replace with actual logic if needed
  filesList.innerHTML = '';
  if (path === '/') {
    const rootItems = ['bin', 'etc', 'home', 'usr', 'var'];
    rootItems.forEach(item => {
      const listItem = document.createElement('li');
      listItem.className = 'fs-item';
      listItem.innerHTML = `<a href="#" onclick="navigate('/' + item)">${item}</a>`;
      filesList.appendChild(listItem);
    });
  } else if (path.startsWith('/home/user')) {
    const userItems = ['Documents', 'Downloads', 'Pictures'];
    userItems.forEach(item => {
      const listItem = document.createElement('li');
      listItem.className = 'fs-item';
      listItem.innerHTML = `<a href="#" onclick="navigate('${path}/${item}')">${item}</a>`;
      filesList.appendChild(listItem);
    });
  } else {
    filesList.innerHTML = '<li>Directory not found</li>';
  }
}

function hideWindow() {
  if (filesWindow.style.display === 'flex') {
    filesWindow.style.display = 'none';
  } else if (notepadWindow.style.display === 'flex') {
    notepadWindow.style.display = 'none';
  }
}

function activateTab(index) {
  tabContent.forEach((tab, i) => {
    tabs.children[i].classList.remove('active');
  });
  tabs.children[index].classList.add('active');
  editor.value = tabContent[index];
  currentTab = index;
}

function newTab() {
  const newTabButton = tabs.children[tabs.children.length];
  const newDiv = document.createElement('div');
  newDiv.id = 'tab-content-' + currentTab;
  tabContent.push(''); // Initialize with empty content
  editor.value = ''; // Clear existing editor content

  newTabButton.before(newDiv);
  activateTab(currentTab);
}


// Load localStorage on page load
window.onload = function() {
    const savedTabs = JSON.parse(localStorage.getItem('notepad_tabs') || '[]');
    tabContent = savedTabs;
    if (savedTabs.length > 0) {
        activateTab(0); // Activate the first tab if it exists
    }
};

// Save localStorage on window unload
window.onbeforeunload = function() {
    localStorage.setItem('notepad_tabs', JSON.stringify(tabContent));
};


openFilesButton.addEventListener('click', () => filesWindow.style.display = 'flex');
openNotepadButton.addEventListener('click', () => notepadWindow.style.display = 'flex');

</script>
</body>
</html>
